mapper.select:
/* FormMypageMapper.countFarPricePlanList */
SELECT COUNT(*)
  FROM VW_GROUP_BY_RATE_INFO@DL_MSP
 WHERE PRV_RATE_CD = #{rateCd}
   AND NXT_APPL_END_DT = '99991231'

mapper.insert:
/* FormMypageMapper.insertServiceAlterTrace 서비스 변경 이력 저장 */
INSERT INTO MSF_SERVICE_ALTER_TRACE (
    NCN
  , CONTRACT_NUM
  , SEQ
  , GLOBAL_NO
  , SUBSCRIBER_NO
  , EVENT_CODE
  , PRCS_MDL_IND
  , TRTM_RSLT_SMST
  , PRCS_SBST
  , RSLT_CD
  , A_SOC_CODE
  , T_SOC_CODE
  , A_SOC_AMNT
  , T_SOC_AMNT
  , PARAMETER
  , ACCESS_IP
  , ACCESS_URL
  , USER_ID
  , SYS_DT
  , SYS_RDATE
) VALUES (
    #{ncn}
  , #{contractNum}
  , (SELECT COALESCE(MAX(SEQ), 0) + 1
       FROM MSF_SERVICE_ALTER_TRACE
      WHERE NCN = #{ncn}
        AND SYS_DT = TO_CHAR(NOW(), 'YYYYMMDD'))
  , #{globalNo}
  , #{subscriberNo}
  , #{eventCode}
  , #{prcsMdlInd}
  , #{trtmRsltSmst}
  , #{prcsSbst}
  , #{rsltCd}
  , #{aSocCode}
  , #{tSocCode}
  , #{aSocAmnt}
  , #{tSocAmnt}
  , #{parameter}
  , #{accessIp}
  , #{accessUrl}
  , #{userId}
  , TO_CHAR(NOW(), 'YYYYMMDD')
  , NOW()
)

mapper.select:
/* FormMypageMapper.checkAllreadPlanchgCount 60분 내 요금제 변경 이력 */
SELECT COUNT(1)
  FROM MSF_SERVICE_ALTER_TRACE
 WHERE NCN = #{ncn}
   AND T_SOC_CODE = #{tSocCode}
   AND SYS_RDATE > NOW() - INTERVAL '1 HOUR'
   AND EVENT_CODE = 'FIN'
   AND TRTM_RSLT_SMST = 'SUCCESS'
   AND SYS_DT = TO_CHAR(NOW(), 'YYYYMMDD')

mapper.insert:
/* FormMypageMapper.insertDisApd 평생할인 부가서비스 INSERT */ INSERT INTO MSP_DIS_APD@DL_MSP ( APD_SEQ , REGST_DT , PROC_YN , CONTRACT_NUM
, PRMT_ID
, CHNL_CD , EVNT_CD , ENGG_MNTH_CNT , OPEN_AGNT_CD , PRMT_AGNT_CD , RATE_CD , ON_OFF_TYPE , OPER_TYPE , REQ_BUY_TYPE , REGST_ID , REGST_DTTM ) SELECT 'AD' || TO_CHAR(SYSDATE, 'YYYYMMDD') || TRIM(TO_CHAR(SQ_DIS_AD.NEXTVAL@DL_MSP, '000000')) , TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') , 'N' , CONTRACT_NUM
, #{prcsMdlInd}
, '01' , 'SCH' , '00' , OPEN_AGNT_CD , '1100011741' , #{tSocCode} , '0' , 'MNP3' , 'UU' , 'MSF' , SYSDATE FROM MSP_JUO_SUB_INFO@DL_MSP WHERE CONTRACT_NUM = #{contractNum}

mapper.update:
/* FormMypageMapper.insertSocfailProcMst 요금제 변경 실패 이력 */
MERGE INTO MSP_SOCFAIL_PROC_MST@DL_MSP
USING DUAL
ON (CONTRACT_NUM = #{contractNum} AND PRCS_MDL_IND = #{prcsMdlInd})
WHEN MATCHED THEN
    UPDATE SET SYS_RDATE = SYSDATE
WHEN NOT MATCHED THEN
    INSERT (
        CONTRACT_NUM
      , PRCS_MDL_IND
      , A_SOC_CODE
      , T_SOC_CODE
      , A_SOC_AMNT
      , T_SOC_AMNT
      , SUCC_YN
      , CHG_TYPE
      , SYS_RDATE
      , PROC_MEMO
      , PROC_YN
      , PROC_ID
    ) VALUES (
        #{contractNum}
      , #{prcsMdlInd}
      , #{aSocCode}
      , #{tSocCode}
      , #{aSocAmnt}
      , #{tSocAmnt}
      , #{succYn}
      , #{chgType}
      , SYSDATE
      , #{procMemo}
      , #{procYn}
      , #{procId}
    )

mapper.select:
/* FormMypageMapper.selectCntrListNoLogin 비회원 계약 현행화 정보 */ SELECT A.SVC_CNTR_NO AS svcCntrNo , A.CONTRACT_NUM AS contractNum , A.CUSTOMER_ID AS custId , A.MODEL_NAME AS modelName , A.MODEL_ID AS modelId , A.SUBSCRIBER_NO AS cntrMobileNo , A.SUB_STATUS AS subStatus , A.DOBYYYYMMDD AS dobyyyymmdd , A.SUB_LINK_NAME AS userName , A.USER_SSN AS unUserSSn , A.LST_COM_ACTV_DATE AS lstComActvDate , B.CUSTOMER_ID AS customerId , B.CUSTOMER_TYPE AS customerType , A.PPPO AS pppo FROM MSP_JUO_SUB_INFO@DL_MSP A , MSP_JUO_CUS_INFO@DL_MSP B WHERE A.CUSTOMER_ID = B.CUSTOMER_ID
AND A.SVC_CNTR_NO = #{svcCntrNo}
AND A.SUBSCRIBER_NO = TRIM(#{cntrMobileNo})
AND UPPER(REPLACE(A.SUB_LINK_NAME, ' ', '')) = UPPER(REPLACE(#{userName}, ' ', ''))
AND A.SUB_STATUS <> 'C'
